alert tcp $HOME_NET any
  -> $EXTERNAL_NET 445
  (msg:"TA0011 T1071.002 Outbound
    SMB to internet possible C2
    or hash relay";
  flow:established,to_server;
  content:"|ff 53 4d 42|"; depth:5;
  classtype:trojan-activity;
  sid:9107106; rev:1;)

alert tcp $HOME_NET any
  -> $HOME_NET 445
  (msg:"TA0006 T1187 PrinterBug
    MS-RPRN spooler coercion";
  flow:established,to_server;
  content:"|78 56 34 12 34 12 cd ab|";
  content:"|41 00 00 00|"; within:50;
  classtype:trojan-activity;
  sid:9118702; rev:1;)

alert udp $HOME_NET any
  -> $HOME_NET 137
  (msg:"TA0007 T1018 NetBIOS NBNS
    name service query burst
    host enumeration";
