    count 30, seconds 60;
  classtype:attempted-recon;
  sid:9101803; rev:1;)

alert tcp $HOME_NET any
  -> $EXTERNAL_NET 445
  (msg:"TA0010 T1048.003 outbound
    SMB to external destination
    extremely anomalous";
