  content:"|fe|SMB"; depth:4;
  classtype:trojan-activity;
  sid:9104804; rev:1;)

alert http $HOME_NET any
  -> $EXTERNAL_NET any
  (msg:"TA0011 T1071.001 HTTP
    beacon Cobalt Strike default
    profile URI";
  flow:established,to_server;
  content:"GET"; http.method;
  pcre:"/^\/(ca|dpixel|fwlink|
    pixel|__utm\.gif|
    jquery-3\.3\.1\.min\.js|
    load|api\/x)(\?|$)/i";
  http.uri;
  threshold:type both,
    track by_src,
    count 5, seconds 3600;
  classtype:trojan-activity;
  sid:9107101; rev:1;)

alert tcp $HOME_NET any
